// Merge arrays
const arr1 = [1, 2];
const arr2 = [3, ...arr1]; // [3, 1, 2]

// Copy object
const obj = { a: 1 };
const objCopy = { ...obj }; // { a: 1 }

// Function parameter passing
const nums = [1, 2, 3];
Math.max(...nums); // Equivalent to Math.max(1, 2, 3)

// Single parameter implicit return
const square = x => x * x;

// Multiple parameters explicit return
const sum = (a, b) => { return a + b; };

// Binding lexical this
const timer = {
 seconds: 0,
 start() {
 setInterval(() => {
 this.seconds++; // Correct access to this
 }, 1000);
 }
};

